row.sprk_jsonschema:
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "title": "FinancialCalculationToolHandler input",
  "type": "object",
  "properties": {
    "formula": {
      "type": "string",
      "enum": [
        "simple_interest",
        "compound_interest",
        "present_value",
        "future_value",
        "loan_payment",
        "roi"
      ]
    },
    "inputs": {
      "type": "object",
      "description": "Named decimal parameters. Required keys per formula: simple_interest=[principal,rate,time]; compound_interest=[principal,rate,time]; present_value=[futureValue,rate,time]; future_value=[presentValue,rate,time]; loan_payment=[principal,rate,periods]; roi=[gain,cost]."
    },
    "options": {
      "type": "object",
      "properties": {
        "precision": { "type": "integer", "minimum": 0, "maximum": 8, "default": 2 },
        "rounding": { "type": "string", "enum": ["banker", "away_from_zero"], "default": "banker" },
        "compoundingFrequency": { "type": "integer", "minimum": 1, "maximum": 365, "default": 1 },
        "currency": { "type": "string", "default": "USD" }
      }
    }
  },
  "required": ["formula", "inputs"]
}
